#include <sstream>
#include <iostream>
#include <iomanip>

// Assume Logger class is defined in the main file

int main() {
    Logger logger;
    std::stringstream ss;
    std::streambuf* oldCout = std::cout.rdbuf();
    std::cout.rdbuf(ss.rdbuf());

    logger.log("Application started.");
    logger.log(101);
    logger.log(true);
    logger.log("Processing data...");
    logger.log(200);
    logger.log(false);
    logger.log("Shutdown initiated.");
    logger.log((const char*)nullptr);

    std::cout.rdbuf(oldCout);
    std::cout << ss.str();

    return 0;
}
